#include <bits/stdc++.h>
using namespace std;
int b[10084];
int main()
{
    int a,c=0;
    b[c]=a;
    while(b[c]!=1)
        {
            if(b[c]%2==0)
            {
                b[c+1]=b[c]/2;
            }
            else
            {
                b[c+1]=b[c]*3+1;
            }
            c+=1;
            cin>>b[c];
        }
    for(int i=10083;i>=0;i--)
        {
            if(b[i]!=0)
            {
                cout<<b[i]<<" ";
            }
        }
    return 0;
}
